// ── Vérification du secret ─────────────────────────────────────────
const expected = $env.N8N_OWNER_WEBHOOK_SECRET || '';
const received  = ($input.first().json.headers || {})['x-webhook-secret'] || '';

// Si un secret est configuré, on vérifie
if (expected && received !== expected) {
  return [{ json: { _authorized: false } }];
}

// ── Extraction du body ────────────────────────────────────────────
const body = $input.first().json.body ?? $input.first().json;

const context = body.context || {};

return [{
  json: {
    _authorized: true,
    message:    String(body.message || '').trim(),
    sessionid:  body.sessionid || null,
    owner_id:   body.owner_id  || null,
    role:       body.role      || 'owner',
    source:     body.source    || 'owner_dashboard',
    context
  }
}];

const ctx     = $json.context || {};
const portfolio = ctx.portfolio || {};
const today     = ctx.today     || [];
const alerts    = ctx.alerts    || [];
const tasks     = ctx.tasks_open || [];
const villas    = ctx.villas    || [];
const stats     = ctx.stats     || {};
const metrics   = stats.metrics || {};

// ── Résumé portfolio ───────────────────────────────────────────────
const portfolioSummary = [
  `Villas : ${portfolio.total_villas ?? 0} total, ${portfolio.published_villas ?? 0} publiée(s)`,
  `CA encaissé : €${(portfolio.total_revenue_paid ?? 0).toLocaleString('fr-FR')}`,
  `Réservations à venir : ${portfolio.upcoming_bookings_count ?? 0}`,
  `Tâches en attente : ${portfolio.pending_tasks_count ?? 0}`,
  metrics.occupancyRate ? `Taux d'occupation : ${metrics.occupancyRate}%` : '',
  metrics.revPAR       ? `RevPAR : €${metrics.revPAR}/nuit`               : ''
].filter(Boolean).join(' | ');

// ── Evénements du jour ─────────────────────────────────────────────
const todaySummary = today.length === 0
  ? 'Aucun événement aujourd\'hui.'
  : today.map(e => {
      const label = e.kind === 'check_in'  ? 'Arrivée'
                  : e.kind === 'check_out' ? 'Départ'
                  : 'En séjour';
      return `${label} : ${e.guest_name || 'Voyageur inconnu'} — ${e.villa_name}`;
    }).join('; ');

// ── Alertes (max 5, priorisées high→low) ──────────────────────────
const SEVERITY_ORDER = { high: 0, medium: 1, low: 2 };
const sortedAlerts = [...alerts].sort(
  (a, b) => (SEVERITY_ORDER[a.severity] ?? 2) - (SEVERITY_ORDER[b.severity] ?? 2)
);
const alertsSummary = sortedAlerts.length === 0
  ? 'Aucune alerte active.'
  : sortedAlerts.slice(0, 5).map(a =>
      `[${a.severity?.toUpperCase() || 'INFO'}] ${a.title}${a.body ? ' — ' + a.body : ''}`
    ).join('; ');

// ── Tâches ouvertes (max 8) ────────────────────────────────────────
const tasksSummary = tasks.length === 0
  ? 'Aucune tâche en attente.'
  : tasks.slice(0, 8).map(t => `• ${t.villa_name}: ${t.content}`).join('; ');

// ── Villas ────────────────────────────────────────────────────────
const villasSummary = villas.length === 0
  ? 'Aucune villa enregistrée.'
  : villas.map(v => `${v.name} (${v.is_published ? 'publiée' : 'non publiée'})`).join(', ');

// ── Alerte stratégique dominante ──────────────────────────────────
const topAlert = sortedAlerts[0] || null;
const strategic_alert = topAlert ? {
  severity:    topAlert.severity || 'low',
  description: topAlert.title + (topAlert.body ? ' — ' + topAlert.body : '')
} : null;

// ── Texte de contexte pour le LLM (compact) ────────────────────────
const contextText = [
  `DATE: ${ctx.current_date_iso ? ctx.current_date_iso.slice(0,10) : 'inconnue'}`,
  `PORTFOLIO: ${portfolioSummary}`,
  `AUJOURD'HUI: ${todaySummary}`,
  `ALERTES: ${alertsSummary}`,
  `TÂCHES: ${tasksSummary}`,
  `VILLAS: ${villasSummary}`
].join('\n');

return [{
  json: {
    ...$json,
    _contextText:     contextText,
    _strategic_alert: strategic_alert,
    _todayCount:      today.length,
    _alertsHighCount: sortedAlerts.filter(a => a.severity === 'high').length,
    _tasksCount:      tasks.length,
    _portfolioStats:  portfolioSummary
  }
}];

const msg = ($json.message || '').toLowerCase();

// Mots-clés → action
const INTENTS = [
  {
    action: 'SHOW_BOOKINGS',
    keywords: ['réservation','reservation','booking','séjour','sejour','arrivée','arrivee','départ','depart','voyageur','client','check-in','check-out','calendrier','agenda']
  },
  {
    action: 'SHOW_VILLAS',
    keywords: ['villa','annonce','propriété','propriete','logement','maison','bien','tarif','prix','nuitée','nuitee','publi']
  },
  {
    action: 'SHOW_TASKS',
    keywords: ['tâche','tache','maintenance','problème','probleme','réparation','reparation','ménage','menage','nettoyage','entretien','panne','dysfonction','urgence','technicien']
  },
  {
    action: 'SHOW_STATS',
    keywords: ['chiffre','revenu','argent','revenue','statistique','stat','performance','taux','occupation','résumé','resume','bilan','portfolio','dashboard','tableau de bord','comment ça va','comment ca va','vue d\'ensemble']
  }
];

let detectedAction = 'SHOW_STATS'; // défaut
for (const intent of INTENTS) {
  if (intent.keywords.some(kw => msg.includes(kw))) {
    detectedAction = intent.action;
    break;
  }
}

// Forcer SHOW_STATS si message très court (salutation, bonjour, etc.)
if (msg.length < 15) detectedAction = 'SHOW_STATS';

return [{
  json: {
    ...$json,
    _detectedAction: detectedAction
  }
}];

// Données issues du nœud précédent (Code Intent) via $('Code — Détection d\'intention')
const intentData = $('Code — Détection d\'intention').first().json;
const strategic_alert  = intentData._strategic_alert  || null;
const detectedAction   = intentData._detectedAction   || 'SHOW_STATS';
const statsPayload     = (intentData.context || {}).stats || null;

// Réponse brute Anthropic
const anthropicRaw = $input.first().json;
const contentBlock = (anthropicRaw.content || [])[0] || {};
const rawText = String(contentBlock.text || anthropicRaw.text || '').trim();

// Tentative de parsing JSON (Claude répond normalement en JSON strict)
let parsed = null;
try {
  // Extraire le JSON même si du texte l'entoure
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  // Claude a répondu en texte libre — on l'encapsule
  parsed = null;
}

const response     = parsed?.response    || rawText || 'Je suis à votre disposition. Comment puis-je vous aider ?';
const action       = parsed?.action      || detectedAction;
const alertFromLLM = parsed?.action_data?.strategic_alert || null;

return [{
  json: {
    response,
    action,
    action_data: {
      context:         statsPayload,
      strategic_alert: alertFromLLM || strategic_alert
    }
  }
}];

// Récupère les données de contexte préparées en amont
const intentData = $('Code — Détection d\'intention').first().json;
const strategic_alert = intentData._strategic_alert || null;
const detectedAction  = intentData._detectedAction  || 'SHOW_STATS';
const statsPayload    = (intentData.context || {}).stats || null;

const hasAlerts   = intentData._alertsHighCount > 0;
const hasToday    = intentData._todayCount > 0;
const hasTasks    = intentData._tasksCount > 0;
const portfolio   = intentData._portfolioStats || '';

let response = '';

if (hasAlerts) {
  response += `⚠️ Attention : ${intentData._alertsHighCount} alerte(s) critique(s) nécessitent votre attention. `;
}

if (hasToday) {
  response += `Aujourd'hui : ${intentData._todayCount} événement(s) en cours sur vos villas. `;
}

if (hasTasks) {
  response += `${intentData._tasksCount} tâche(s) sont en attente de traitement. `;
}

if (!response) {
  response = `Bonjour ! Votre tableau de bord est actif. ${portfolio}. Je reste disponible pour toute question.`;
} else {
  response += `Résumé : ${portfolio}.`;
}

response += ' (Service IA temporairement limité — données en temps réel disponibles.)';

return [{
  json: {
    response,
    action: detectedAction,
    action_data: {
      context: statsPayload,
      strategic_alert
    }
  }
}];
